import React, { useState } from "react";
import AiChat from "./AiChat";
import "./FloatingAiButton.css";

export default function FloatingAiButton({ context, disabled = false }) {
  const [isOpen, setIsOpen] = useState(false);

  if (!context || disabled) return null;

  return (
    <>
      {/* Floating Button */}
      <button 
        className="floating-ai-button"
        onClick={() => setIsOpen(true)}
        title="Open AI Chat"
        aria-label="Open AI Chat"
      >
        <span className="floating-ai-icon">🧠</span>
      </button>

      {/* Modal Overlay */}
      {isOpen && (
        <div className="ai-chat-modal-overlay" onClick={() => setIsOpen(false)}>
          {/* Modal Container */}
          <div className="ai-chat-modal" onClick={e => e.stopPropagation()}>
            {/* Modal Header */}
            <div className="ai-chat-modal-header">
              <h2 className="ai-chat-modal-title">Ask Your Data</h2>
              <button 
                className="ai-chat-modal-close"
                onClick={() => setIsOpen(false)}
                aria-label="Close AI Chat"
              >
                ✕
              </button>
            </div>

            {/* Modal Content */}
            <div className="ai-chat-modal-content">
              <AiChat context={context} compact={true} />
            </div>
          </div>
        </div>
      )}
    </>
  );
}
